// Interactive state-machine widget for the ROSNode docs.
//
// Renders each `<div class="rosnode-statechart" data-machine="ID">` from
// window.ROSNODE_MACHINES (generated by docs/statemachines.jl). Two views of one
// source-generated machine:
//   • a static Mermaid schematic (the whole graph at a glance), loaded from CDN;
//   • an interactive stepper driven by XState (window.XState, vendored).
// The active state highlights live on the schematic as you step. If the mermaid CDN
// is unreachable the schematic is skipped and the stepper (with a state-chip fallback)
// still works; if XState is absent a tiny built-in interpreter takes over.
(function () {
  "use strict";

  var MERMAID_BASE = "https://cdn.jsdelivr.net/npm/mermaid@10/dist/mermaid.min"; // no .js — RequireJS appends it
  var MERMAID_SRC = MERMAID_BASE + ".js";
  var _mermaidPromise = null;
  var _uid = 0;

  function initMermaid(m) {
    try { m.initialize({ startOnLoad: false, securityLevel: "loose", theme: "neutral" }); } catch (e) { /* render() surfaces real failures */ }
    return m;
  }

  // Load mermaid from CDN once, shared across every widget on the page.
  //
  // Documenter ships RequireJS. Loading mermaid's UMD via a bare <script> makes its
  // AMD branch call an anonymous define() that RequireJS rejects ("Mismatched
  // anonymous define()"). So when an AMD loader is present we load mermaid THROUGH it
  // (the anonymous define is then captured under the configured module id); otherwise
  // we fall back to a plain <script>.
  function loadMermaid() {
    if (window.mermaid) return Promise.resolve(initMermaid(window.mermaid));
    if (_mermaidPromise) return _mermaidPromise;
    _mermaidPromise = new Promise(function (resolve, reject) {
      if (typeof window.require === "function" && window.define && window.define.amd) {
        try { window.require.config({ paths: { mermaid_cdn: MERMAID_BASE } }); } catch (e) {}
        window.require(
          ["mermaid_cdn"],
          function (m) { resolve(initMermaid(m || window.mermaid)); },
          function (err) { reject(err || new Error("mermaid CDN unavailable")); }
        );
        return;
      }
      var s = document.createElement("script");
      s.src = MERMAID_SRC;
      s.onload = function () { resolve(initMermaid(window.mermaid)); };
      s.onerror = function () { reject(new Error("mermaid CDN unavailable")); };
      document.head.appendChild(s);
    });
    return _mermaidPromise;
  }

  // Map each rendered Mermaid state node to its <g>, so the stepper can highlight it.
  // State names and event (edge) labels are disjoint in these machines, so matching a
  // group's text against the state set is unambiguous.
  function mapSchematicNodes(container, states) {
    var map = {};
    var groups = container.querySelectorAll("g.node, g.statediagram-state, g[id]");
    Array.prototype.forEach.call(groups, function (g) {
      var t = (g.textContent || "").trim();
      if (states.indexOf(t) !== -1 && !map[t] && g.querySelector("rect, polygon, circle, path")) {
        map[t] = g;
      }
    });
    return map;
  }

  // Drive transitions through XState when present; else interpret the flat config.
  function makeRunner(def) {
    var cfg = def.machine;
    if (window.XState && typeof window.XState.createActor === "function") {
      var actor = window.XState.createActor(window.XState.createMachine(cfg));
      actor.start();
      return {
        value: function () { return String(actor.getSnapshot().value); },
        send: function (ev) { actor.send({ type: ev }); },
        reset: function () { actor.stop(); actor = window.XState.createActor(window.XState.createMachine(cfg)); actor.start(); }
      };
    }
    var current = cfg.initial;
    return {
      value: function () { return current; },
      send: function (ev) { var on = (cfg.states[current] || {}).on || {}; if (on[ev]) current = on[ev]; },
      reset: function () { current = cfg.initial; }
    };
  }

  function enabledEvents(def, state) { return Object.keys((def.machine.states[state] || {}).on || {}); }
  function targetOf(def, state, ev) { return ((def.machine.states[state] || {}).on || {})[ev]; }
  function metaOf(def, state) { return ((def.meta || {}).states || {})[state] || { kind: "primary", desc: "" }; }
  function isFinal(def, state) { return (def.machine.states[state] || {}).type === "final"; }

  function el(tag, cls, text) {
    var e = document.createElement(tag);
    if (cls) e.className = cls;
    if (text != null) e.textContent = text;
    return e;
  }

  function render(host, def) {
    var runner = makeRunner(def);
    host.textContent = "";
    host.classList.add("sc-ready");
    var stateOrder = Object.keys(def.machine.states);

    var head = el("div", "sc-head");
    head.appendChild(el("div", "sc-title", def.title));
    head.appendChild(el("div", "sc-summary", def.summary));
    host.appendChild(head);

    // The schematic — the whole machine at a glance. Rendered by Mermaid from the
    // source-generated `def.mermaid`; nodes are clickable (inspect) and highlight live.
    var schematic = el("div", "sc-schematic");
    host.appendChild(schematic);
    var schematicNodes = null;

    // State chips: the fallback view + always-available inspect. Hidden once the
    // schematic renders (its nodes take over inspection).
    var chips = el("div", "sc-states");
    var chipByState = {};
    stateOrder.forEach(function (s) {
      var chip = el("button", "sc-chip sc-kind-" + metaOf(def, s).kind, s);
      chip.setAttribute("type", "button");
      chip.addEventListener("click", function () { showState(s); });
      chipByState[s] = chip;
      chips.appendChild(chip);
    });
    host.appendChild(chips);

    var desc = el("div", "sc-desc");
    host.appendChild(desc);

    var controls = el("div", "sc-controls");
    controls.appendChild(el("span", "sc-ev-label", "Transitions:"));
    var evWrap = el("span", "sc-events");
    var reset = el("button", "sc-reset", "↺ reset");
    reset.setAttribute("type", "button");
    reset.addEventListener("click", function () { runner.reset(); inspecting = null; update(); });
    controls.appendChild(evWrap);
    controls.appendChild(reset);
    host.appendChild(controls);

    var pathWrap = el("div", "sc-path");
    pathWrap.appendChild(el("span", "sc-path-label", "Path:"));
    var pathList = el("span", "sc-path-list");
    pathWrap.appendChild(pathList);
    host.appendChild(pathWrap);

    var path = [];
    var inspecting = null;

    function showState(s) { inspecting = s; paint(); }
    function step(ev) {
      var from = runner.value();
      runner.send(ev);
      var to = runner.value();
      if (to !== from) path.push({ ev: ev, state: to });
      inspecting = null;
      paint();
    }
    function update() { path = []; paint(); }

    function paint() {
      var active = runner.value();
      var shown = inspecting || active;

      stateOrder.forEach(function (s) {
        chipByState[s].classList.toggle("sc-active", s === active);
        chipByState[s].classList.toggle("sc-inspect", s === inspecting && s !== active);
        if (schematicNodes && schematicNodes[s]) {
          schematicNodes[s].classList.toggle("sc-node-active", s === active);
          schematicNodes[s].classList.toggle("sc-node-inspect", s === inspecting && s !== active);
        }
      });

      var m = metaOf(def, shown);
      desc.textContent = "";
      desc.appendChild(el("span", "sc-desc-name", shown));
      desc.appendChild(el("span", "sc-desc-text", m.desc));

      evWrap.textContent = "";
      var events = enabledEvents(def, active);
      if (events.length === 0) {
        evWrap.appendChild(el("span", "sc-terminal", isFinal(def, active) ? "(terminal state)" : "(no transitions)"));
      } else {
        events.forEach(function (ev) {
          var b = el("button", "sc-event", ev);
          b.setAttribute("type", "button");
          b.title = "→ " + targetOf(def, active, ev);
          b.addEventListener("click", function () { step(ev); });
          evWrap.appendChild(b);
        });
      }

      pathList.textContent = "";
      pathList.appendChild(el("span", "sc-path-node", def.machine.initial));
      path.forEach(function (h) {
        pathList.appendChild(el("span", "sc-path-ev", " —" + h.ev + "→ "));
        pathList.appendChild(el("span", "sc-path-node", h.state));
      });
    }

    // Kick off the schematic; the stepper is fully usable before/without it.
    if (def.mermaid) {
      loadMermaid()
        .then(function (m) { return m.render("scmmd-" + (++_uid), def.mermaid); })
        .then(function (out) {
          schematic.innerHTML = out.svg;
          var svg = schematic.querySelector("svg");
          if (svg) { svg.removeAttribute("width"); svg.style.maxWidth = "100%"; svg.style.height = "auto"; }
          schematicNodes = mapSchematicNodes(schematic, stateOrder);
          Object.keys(schematicNodes).forEach(function (s) {
            var g = schematicNodes[s];
            g.style.cursor = "pointer";
            g.addEventListener("click", function () { showState(s); });
          });
          chips.style.display = "none";   // schematic supersedes the chip row
          paint();
        })
        .catch(function () { schematic.style.display = "none"; });   // keep the stepper + chips
    } else {
      schematic.style.display = "none";
    }

    paint();
  }

  function init() {
    if (!window.ROSNODE_MACHINES) return;
    var hosts = document.querySelectorAll(".rosnode-statechart");
    Array.prototype.forEach.call(hosts, function (host) {
      var id = host.getAttribute("data-machine");
      var def = window.ROSNODE_MACHINES[id];
      if (def) render(host, def);
      else host.textContent = "[state machine '" + id + "' not found]";
    });
  }

  if (document.readyState === "loading") document.addEventListener("DOMContentLoaded", init);
  else init();
})();
